class Cache {
  constructor() {
    this.store = new Map();
  }

  set(key, value) {
    this.store.set(key, { value, timestamp: Date.now() });
  }

  get(key) {
    return this.store.get(key)?.value;
  }

  delete(key) {
    this.store.delete(key);
  }
}

module.exports = new Cache();

const EventEmitter = require('events');

class EventBus extends EventEmitter {
  constructor() {
    super();
    this.setMaxListeners(0); // suppress warnings
  }
}

module.exports = new EventBus();

const cache = require('../cache');
const eventBus = require('../eventBus');

router.get('/data/:id', async (req, res) => {
  const { id } = req.params;

  const cached = cache.get(id);
  if (cached) return res.json(cached);

  const data = await fetchData(id);
  cache.set(id, data);

  // Listen for updates
  eventBus.on('data-updated', (updatedId) => {
    if (updatedId === id) cache.delete(id);
  });

  res.json(data);
});

const DEFAULT_TTL_MS = 5 * 60 * 1000; // 5 minutes
const MAX_ENTRIES = 10000;

class Cache {
  constructor(ttlMs = DEFAULT_TTL_MS, maxEntries = MAX_ENTRIES) {
    this.store = new Map();
    this.ttlMs = ttlMs;
    this.maxEntries = maxEntries;
    // Periodic cleanup every minute
    this.cleanupInterval = setInterval(() => this._evictExpired(), 60 * 1000);
    this.cleanupInterval.unref(); // don't block process exit
  }

  set(key, value) {
    if (this.store.size >= this.maxEntries) this._evictOldest();
    this.store.set(key, { value, expiresAt: Date.now() + this.ttlMs });
  }

  get(key) {
    const entry = this.store.get(key);
    if (!entry) return undefined;
    if (Date.now() > entry.expiresAt) {
      this.store.delete(key);
      return undefined;
    }
    return entry.value;
  }

  delete(key) { this.store.delete(key); }

  _evictExpired() {
    const now = Date.now();
    for (const [key, entry] of this.store) {
      if (now > entry.expiresAt) this.store.delete(key);
    }
  }

  _evictOldest() {
    const oldest = this.store.keys().next().value;
    if (oldest) this.store.delete(oldest);
  }
}

module.exports = new Cache();

const cache = require('../cache');
const eventBus = require('../eventBus');

// Register the cache invalidation listener once at startup
eventBus.on('data-updated', (updatedId) => {
  cache.delete(updatedId);
});

router.get('/data/:id', async (req, res) => {
  const { id } = req.params;
  const cached = cache.get(id);
  if (cached) return res.json(cached);
  const data = await fetchData(id);
  cache.set(id, data);
  res.json(data);
});
